#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAX 1000000000000000000
long long powmod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}
long long inv(long long a, long long mod) {
    return powmod(a, mod - 2, mod);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long X, Y, S;
        scanf("%lld %lld %lld", &X, &Y, &S);
        long long u, v;
        scanf("%lld %lld", &u, &v);
        long long p = u * inv(v, MOD) % MOD;
        long long q = (1 - p + MOD) % MOD;
        long long ans = 0;
        long long curr = 1;
        while (curr < S) {
            if (curr % X == 0) {
                ans = (ans + p * curr) % MOD;
                curr *= 2;
            } else if (curr % Y == 0) {
                ans = (ans + q * curr) % MOD;
                curr *= 2;
            } else {
                ans = (ans + (p + q) * curr) % MOD;
                curr *= 2;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

